const body = $input.item.json.body;

let riasecScores;
try {
  riasecScores = typeof body.riasecScores === 'string' ? JSON.parse(body.riasecScores) : (body.riasecScores || { R:0,I:0,A:0,S:0,E:0,C:0 });
} catch(e) { riasecScores = { R:0,I:0,A:0,S:0,E:0,C:0 }; }

let history = [];
try {
  history = typeof body.history === 'string' ? JSON.parse(body.history) : (body.history || []);
} catch(e) { history = []; }

const s = riasecScores;
const scoresPipe = 'R:' + s.R + '|I:' + s.I + '|A:' + s.A + '|S:' + s.S + '|E:' + s.E + '|C:' + s.C;
const sorted = Object.entries(riasecScores).sort((a, b) => b[1] - a[1]).map(x => ({ dim: x[0], score: x[1] }));
const hollandCode = sorted.slice(0, 3).map(x => x.dim).join('');
const historyText = history.filter(h => h.role === 'user').map(h => h.content).slice(-10).join(' | ');

const systemPrompt = 'Sos un psicólogo vocacional experto en Holland RIASEC. Analizás perfiles y generás informes profesionales en español rioplatense.\n\n' +
  'FORMATO REQUERIDO (RESPONDÉ SOLO JSON PURO SIN MARKDOWN):\n' +
  '{\n  "hollandCode": "XYZ",\n  "perfilTitulo": "título creativo",\n  "perfilDescripcion": "párrafo 80-100 palabras",\n  "fortalezas": ["f1","f2","f3","f4"],\n  "areasDesarrollo": ["a1","a2","a3"],\n  "carreras": [{\"nombre\":\"Carrera\",\"match\":95,\"descripcion\":\"desc\",\"area\":\"campo\",\"duracion\":\"4 años\",\"salida\":\"laboral\"}],\n  "consejosEstudio": ["c1","c2","c3"],\n  "fraseMotivadora": "frase"\n}\n\nGenerá exactamente 5 carreras.';

const userPrompt = 'Analizá este perfil:\n\nUsuario: ' + (body.userName || 'Estudiante') + '\nCódigo Holland: ' + hollandCode + '\nScores RIASEC: ' + scoresPipe + '\n\nRespuestas: ' + (historyText || 'No disponible') + '\n\nGenerá el informe completo.';

return [{ json: {
  sessionId: body.sessionId,
  userId: body.userId || null,
  tenantId: body.tenantId || null,
  plan: body.plan || 'b2c',
  email: body.email || null,
  userName: body.userName || 'Estudiante',
  riasecScores: riasecScores,
  scoresPipe: scoresPipe,
  hollandCode: hollandCode,
  sortedDims: sorted,
  requestBody: JSON.stringify({
    model: 'gpt-4o',
    max_tokens: 1800,
    temperature: 0.65,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ]
  })
} }];

try {
  const raw = $input.item.json.choices[0].message.content;
  if (!raw) throw new Error('Sin respuesta OpenAI');

  const meta = $('[Code] Preparar análisis RIASEC').item.json;
  const cleaned = raw.replace(/^```json?\n?/, '').replace(/\n?```$/, '').trim();
  const analysis = JSON.parse(cleaned);

  return [{ json: {
    sessionId: meta.sessionId,
    userId: meta.userId,
    tenantId: meta.tenantId,
    plan: meta.plan,
    email: meta.email,
    userName: meta.userName,
    hollandCode: analysis.hollandCode || meta.hollandCode,
    riasecScores: meta.riasecScores,
    sortedDims: meta.sortedDims,
    perfilTitulo: analysis.perfilTitulo || '',
    perfilDescripcion: analysis.perfilDescripcion || '',
    fortalezas: analysis.fortalezas || [],
    areasDesarrollo: analysis.areasDesarrollo || [],
    carreras: analysis.carreras || [],
    consejosEstudio: analysis.consejosEstudio || [],
    fraseMotivadora: analysis.fraseMotivadora || '',
    generadoEn: new Date().toISOString(),
    status: 'READY'
  } }];
} catch(e) { 
  throw new Error('[Parse resultado] ' + e.message); 
}

try {
  const resultado = $input.item.json;
  if (!resultado.email) {
    return [{ json: { ...resultado, skipEmail: true } }];
  }

  const dims = { R: 'Realista', I: 'Investigador', A: 'Artístico', S: 'Social', E: 'Emprendedor', C: 'Convencional' };
  const scores = resultado.riasecScores || {};
  const maxScore = Math.max(...Object.values(scores), 1);

  const riasecBars = Object.entries(scores).sort((a, b) => b[1] - a[1]).map(([k, v]) => {
    const pct = Math.round((v / maxScore) * 100);
    const isTop = pct >= 70;
    return '<tr><td style="padding:5px;font-size:13px;font-weight:' + (isTop ? '700' : '400') + ';color:' + (isTop ? '#4f46e5' : '#374151') + ';width:130px">' + dims[k] + '</td><td style="padding:5px"><table style="width:220px;background:#e5e7eb;border-radius:4px;height:14px"><tr><td style="background:' + (isTop ? '#4f46e5' : '#818cf8') + ';width:' + pct + '%;border-radius:4px;height:14px"></td></tr></table></td><td style="padding:5px;font-size:12px;color:#9ca3af">' + v + ' pts</td></tr>';
  }).join('');

  const carrerasHTML = (resultado.carreras || []).map((c, i) => {
    return '<div style="border:1px solid #e5e7eb;border-radius:8px;margin:12px 0;padding:16px"><h3 style="margin:0 0 8px;font-size:15px;font-weight:700;color:#1f2937">' + (i+1) + '. ' + c.nombre + '</h3><span style="background:#4f46e5;color:white;padding:3px 10px;border-radius:12px;font-size:12px">' + c.match + '% match</span><p style="margin:8px 0;font-size:13px;color:#4b5563">' + c.descripcion + '</p><span style="font-size:11px;color:#9ca3af">📚 ' + c.area + ' · ⏱ ' + c.duracion + ' · 💼 ' + c.salida + '</span></div>';
  }).join('');

  const fortalezasHTML = (resultado.fortalezas || []).map(f => '<li style="font-size:14px;color:#374151;line-height:1.8">' + f + '</li>').join('');
  const consejosHTML = (resultado.consejosEstudio || []).map(c => '<li style="font-size:14px;color:#374151;line-height:1.8">' + c + '</li>').join('');
  const fecha = new Date().toLocaleDateString('es-AR', { day: 'numeric', month: 'long', year: 'numeric' });

  const htmlReport = '<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Tu Informe Vocacional</title></head><body style="margin:0;padding:0;background:#f3f4f6"><table width="100%" style="background:#f3f4f6;padding:32px"><tr><td align="center"><table width="600" style="background:white;border-radius:12px;overflow:hidden"><tr><td style="background:#4f46e5;padding:40px;text-align:center"><p style="margin:0 0 8px;font-size:11px;color:rgba(255,255,255,0.7);text-transform:uppercase;letter-spacing:3px">Informe Vocacional</p><h1 style="margin:0 0 16px;font-size:24px;font-weight:700;color:white">' + resultado.perfilTitulo + '</h1><table align="center"><tr><td style="padding:0 4px"><span style="display:inline-block;background:rgba(255,255,255,0.2);border:2px solid rgba(255,255,255,0.5);border-radius:8px;width:44px;height:44px;text-align:center;line-height:44px;font-size:22px;font-weight:900;color:white">' + resultado.hollandCode[0] + '</span></td><td style="padding:0 4px"><span style="display:inline-block;background:rgba(255,255,255,0.2);border:2px solid rgba(255,255,255,0.5);border-radius:8px;width:44px;height:44px;text-align:center;line-height:44px;font-size:22px;font-weight:900;color:white">' + resultado.hollandCode[1] + '</span></td><td style="padding:0 4px"><span style="display:inline-block;background:rgba(255,255,255,0.2);border:2px solid rgba(255,255,255,0.5);border-radius:8px;width:44px;height:44px;text-align:center;line-height:44px;font-size:22px;font-weight:900;color:white">' + resultado.hollandCode[2] + '</span></td></tr></table><p style="margin:12px 0 0;font-size:12px;color:rgba(255,255,255,0.6)">Código Holland</p></td></tr><tr><td style="padding:32px"><p style="margin:0 0 8px;font-size:14px;color:#9ca3af">Hola, <strong style="color:#1f2937">' + resultado.userName + '</strong></p><p style="margin:0 0 32px;font-size:15px;color:#374151;line-height:1.7">' + resultado.perfilDescripcion + '</p><h2 style="margin:0 0 16px;font-size:16px;font-weight:700;color:#1f2937;border-bottom:2px solid #e5e7eb;padding-bottom:8px">📊 Tu perfil RIASEC</h2><table>' + riasecBars + '</table><h2 style="margin:32px 0 16px;font-size:16px;font-weight:700;color:#1f2937;border-bottom:2px solid #e5e7eb;padding-bottom:8px">⭐ Tus fortalezas</h2><ul style="padding-left:20px">' + fortalezasHTML + '</ul><h2 style="margin:32px 0 16px;font-size:16px;font-weight:700;color:#1f2937;border-bottom:2px solid #e5e7eb;padding-bottom:8px">🎓 Carreras recomendadas</h2>' + carrerasHTML + '<h2 style="margin:32px 0 16px;font-size:16px;font-weight:700;color:#1f2937;border-bottom:2px solid #e5e7eb;padding-bottom:8px">💡 Consejos</h2><ol style="padding-left:20px">' + consejosHTML + '</ol><table width="100%" style="background:#f5f3ff;border-left:4px solid #4f46e5;border-radius:4px;margin:32px 0"><tr><td style="padding:20px"><p style="margin:0;font-family:Georgia,serif;font-size:16px;color:#4f46e5;font-style:italic">&ldquo;' + resultado.fraseMotivadora + '&rdquo;</p></td></tr></table></td></tr><tr><td style="background:#f9fafb;padding:24px;text-align:center;border-top:1px solid #e5e7eb"><p style="margin:0;font-size:11px;color:#9ca3af">Informe generado el ' + fecha + ' · Test Vocacional Profesional</p></td></tr></table></td></tr></table></body></html>';

  return [{ json: { ...resultado, htmlReport: htmlReport, skipEmail: false } }];
} catch(e) {
  throw new Error('[Build HTML] ' + e.message);
}
